const allowedOrigins = [
	process.env.CORS_ORIGIN || "",
	process.env.CORS_ORIGIN_2 || "",
	...Array.from({ length: 10 }, (_, i) => `http://localhost:${5170 + i}`)
].filter(Boolean);
const auth = betterAuth({
	database: prismaAdapter(prisma, { provider: "postgresql" }),
	baseURL: process.env.BETTER_AUTH_URL,
	basePath: "/api",
	plugins: [username(), openAPI()],
	user: { additionalFields: {
		role: {
			type: "string",
			input: true,
			required: false,
			defaultValue: "STUDENT",
			fieldName: "role"
		},
		grade: {
			type: "number",
			input: true,
			required: false,
			defaultValue: 0,
			fieldName: "grade"
		},
		classLabel: {
			type: "string",
			input: true,
			required: false,
			fieldName: "classLabel"
		},
		guardianEmail: {
			type: "string",
			input: true,
			required: false,
			fieldName: "guardianEmail"
		},
		gender: {
			type: "string",
			input: true,
			required: false,
			fieldName: "gender"
		},
		totalXp: {
			type: "number",
			input: false,
			fieldName: "totalXp",
			defaultValue: 0
		}
	} },
	trustedOrigins: allowedOrigins,
	emailAndPassword: { enabled: true },
	advanced: { defaultCookieAttributes: {
		sameSite: process.env.NODE_ENV === "production" ? "none" : "lax",
		secure: process.env.NODE_ENV === "production",
		httpOnly: true
	} }
});
let _schema;
const getSchema = async () => _schema ??= auth.api.generateOpenAPISchema();
const OpenAPI = {
	getPaths: (prefix = "/auth/api") => getSchema().then(({ paths }) => {
		const reference = Object.create(null);
		for (const path of Object.keys(paths)) {
			const key = prefix + path;
			reference[key] = paths[path];
			for (const method of Object.keys(paths[path])) {
				const operation = reference[key][method];
				operation.tags = ["Better Auth"];
			}
		}
		return reference;
	}),
	components: getSchema().then(({ components }) => components)
};
