/**
* Helper function to calculate Normalized Gain (N-Gain)
*/
const calculateNGain = (pre, post) => {
	if (pre >= 100) return post >= 100 ? 100 : 0;
	return (post - pre) / (100 - pre) * 100;
};
/**
* Get students filtered by grade
*/
const getStudentsByGrade = async (grade, classLabel, search, gender) => {
	return (await prisma.user.findMany({
		where: {
			grade,
			role: "STUDENT",
			...classLabel ? { classLabel: {
				equals: classLabel,
				mode: "insensitive"
			} } : {},
			...gender ? { gender: {
				equals: gender,
				mode: "insensitive"
			} } : {},
			...search ? { OR: [{ name: {
				contains: search,
				mode: "insensitive"
			} }, { username: {
				contains: search,
				mode: "insensitive"
			} }] } : {}
		},
		select: {
			id: true,
			name: true,
			email: true,
			username: true,
			displayUsername: true,
			grade: true,
			classLabel: true,
			guardianEmail: true,
			role: true,
			totalXp: true,
			gender: true,
			storyAttempts: {
				where: {
					preTestScore: { not: null },
					postTestScore: { not: null }
				},
				select: {
					preTestScore: true,
					postTestScore: true
				}
			},
			quizAttempts: {
				where: { completed: true },
				select: {
					islandSlug: true,
					topicSlug: true,
					levelId: true,
					percentageScore: true,
					startedAt: true
				},
				orderBy: { startedAt: "asc" }
			}
		},
		orderBy: { name: "asc" }
	})).map((s) => {
		let sumImp = 0;
		let countImp = 0;
		for (const sa of s.storyAttempts) {
			sumImp += calculateNGain(Number(sa.preTestScore), Number(sa.postTestScore));
			countImp++;
		}
		const learningImprovement = countImp > 0 ? Math.round(sumImp / countImp) : 0;
		const firstAttemptsMap = /* @__PURE__ */ new Map();
		for (const qa of s.quizAttempts) {
			const key = `${qa.islandSlug}::${qa.topicSlug}::${qa.levelId}`;
			if (!firstAttemptsMap.has(key)) firstAttemptsMap.set(key, qa);
		}
		const firstAttempts = Array.from(firstAttemptsMap.values());
		let sumLit = 0;
		let countLit = 0;
		for (const qa of firstAttempts) {
			sumLit += qa.percentageScore;
			countLit++;
		}
		const averageLiteracyScore = countLit > 0 ? Math.round(sumLit / countLit) : 0;
		return {
			id: s.id,
			name: s.name,
			email: s.email,
			username: s.username,
			displayUsername: s.displayUsername,
			grade: s.grade,
			classLabel: s.classLabel,
			guardianEmail: s.guardianEmail,
			role: s.role,
			totalXp: s.totalXp,
			gender: s.gender,
			learningImprovement,
			averageLiteracyScore
		};
	});
};
