/**
* Service layer for Quiz Attempts domain
* Follows the same pattern as routes/attempts/service.ts
*/
const ALLOWED_SORT_FIELDS = [
	"startedAt",
	"finishedAt",
	"xpGained",
	"percentageScore",
	"id"
];
/**
* Submit (create) a completed quiz attempt
* Also increments user.totalXp
*/
async function submitQuizAttempt(userId, data) {
	if (data.score > data.totalQuestions) throw new Error("Score cannot be greater than total questions");
	if (data.xpGained < 0) throw new Error("xpGained cannot be negative");
	const percentageScore = data.totalQuestions > 0 ? data.score / data.totalQuestions * 100 : 0;
	const resolvedQuizType = data.quizType ?? {
		1: "Ingatan",
		2: "Analisis",
		3: "Pendapat"
	}[data.levelId] ?? "culture";
	const existingAttempt = await prisma.quizAttempt.findFirst({ where: {
		userId,
		islandSlug: data.islandSlug,
		topicSlug: data.topicSlug,
		levelId: data.levelId,
		completed: true
	} });
	const finalXpGained = existingAttempt ? 0 : 100;
	const [attempt] = await prisma.$transaction([prisma.quizAttempt.create({ data: {
		userId,
		islandSlug: data.islandSlug,
		topicSlug: data.topicSlug,
		levelId: data.levelId,
		quizType: resolvedQuizType,
		finishedAt: /* @__PURE__ */ new Date(),
		completed: true,
		totalTimeSeconds: data.totalTimeSeconds,
		xpGained: finalXpGained,
		score: data.score,
		totalQuestions: data.totalQuestions,
		percentageScore,
		wrongAttempts: data.wrongAttempts ?? 0,
		heartsLeft: data.heartsLeft ?? 5
	} }), prisma.user.update({
		where: { id: userId },
		data: { totalXp: { increment: finalXpGained } }
	})]);
	return {
		...attempt,
		isReplay: !!existingAttempt
	};
}
/**
* Get paginated list of quiz attempts for a user
*
* NOTE: `completed` is handled separately — NOT through buildWhereClause —
* because buildWhereClause calls String(value) internally, which converts
* boolean `true` to the string "true". PostgreSQL boolean columns don't
* match string literals, so the WHERE clause would silently return 0 rows.
* This mirrors the pattern used for `isFinished` in attempts/service.ts.
*/
async function getQuizAttempts(userId, pagination, filters = {}) {
	const filterClause = buildWhereClause({
		islandSlug: filters.islandSlug,
		topicSlug: filters.topicSlug,
		levelId: filters.levelId
	}, [
		"islandSlug",
		"topicSlug",
		"levelId"
	]);
	const completedClause = filters.completed !== void 0 ? { completed: filters.completed } : void 0;
	const where = combineWhereClauses({ userId }, filterClause, completedClause);
	return paginatedQuery((options) => prisma.quizAttempt.findMany({
		...options,
		where
	}), pagination, {
		allowedSortFields: ALLOWED_SORT_FIELDS,
		defaultSortField: "startedAt"
	});
}
