const TOTAL_LEVELS_PER_ISLAND = 9;
function deriveBadge(maxLevelCompleted) {
	if (maxLevelCompleted >= 3) return "Pakar Budaya";
	if (maxLevelCompleted >= 2) return "Penjelajah Budaya";
	if (maxLevelCompleted >= 1) return "Pengamat Budaya";
	return "-";
}
async function getQuizStatistics(userId) {
	const [completedAttempts, xpResult] = await Promise.all([prisma.quizAttempt.findMany({
		where: {
			userId,
			completed: true
		},
		orderBy: { startedAt: "asc" },
		select: {
			islandSlug: true,
			topicSlug: true,
			levelId: true,
			percentageScore: true,
			xpGained: true
		}
	}), prisma.user.findUnique({
		where: { id: userId },
		select: { totalXp: true }
	})]);
	const firstAttemptsMap = /* @__PURE__ */ new Map();
	for (const a of completedAttempts) {
		const key = `${a.islandSlug}::${a.topicSlug}::${a.levelId}`;
		if (!firstAttemptsMap.has(key)) firstAttemptsMap.set(key, a);
	}
	const firstAttempts = Array.from(firstAttemptsMap.values());
	const levelsCompleted = firstAttempts.length;
	const totalPercentageScore = firstAttempts.reduce((sum, a) => sum + a.percentageScore, 0);
	const averageScore = firstAttempts.length > 0 ? Math.round(totalPercentageScore / firstAttempts.length) : 0;
	const currentBadge = deriveBadge(firstAttempts.length > 0 ? Math.max(...firstAttempts.map((a) => a.levelId)) : 0);
	const totalXpFromQuiz = completedAttempts.reduce((sum, a) => sum + a.xpGained, 0);
	const islandLevelMap = {};
	for (const a of firstAttempts) {
		const key = `${a.topicSlug}::${a.levelId}`;
		if (!islandLevelMap[a.islandSlug]) islandLevelMap[a.islandSlug] = /* @__PURE__ */ new Set();
		islandLevelMap[a.islandSlug].add(key);
	}
	const islandExploration = Object.entries(islandLevelMap).map(([islandSlug, levels]) => ({
		islandSlug,
		levelsCompleted: levels.size,
		totalLevels: TOTAL_LEVELS_PER_ISLAND,
		isFullyCompleted: levels.size >= TOTAL_LEVELS_PER_ISLAND
	}));
	return {
		levelsCompleted,
		totalXpFromQuiz,
		averageScore,
		islandsFullyCompleted: islandExploration.filter((i) => i.isFullyCompleted).length,
		currentBadge,
		islandExploration
	};
}
//#endregion
//#region src/routes/quiz-statistics/index.ts
/**
* Quiz Statistics API routes (requires authentication)
* Follows the same pattern as routes/statistics/index.ts
*/
const quizStatisticsRoutes = new Elysia({ prefix: "/quiz-statistics" }).derive(async ({ request, set }) => {
	if (request.method === "OPTIONS") return { user: null };
	const session = await auth.api.getSession({ headers: request.headers });
	if (!session?.user) {
		set.status = 401;
		return { user: null };
	}
	return { user: session.user };
}).get("/", async ({ user, set }) => {
	if (!user) {
		set.status = 401;
		return {
			error: "Unauthorized",
			code: "UNAUTHORIZED"
		};
	}
	return await getQuizStatistics(user.id);
}, {
	detail: {
		tags: ["Quiz Statistics"],
		summary: "Get quiz statistics",
		description: "Returns levels completed, total XP from quiz, average score, islands explored, and current badge"
	},
	response: {
		200: QuizStatisticsSchema,
		401: ErrorResponseSchema
	}
});
//#endregion
//#region src/routes/index.ts
/**
* API Routes aggregator
* Combines all domain routes under /api prefix
*/
const apiRoutes = new Elysia({ prefix: "/api" }).use(islandRoutes).use(storyRoutes).use(questionRoutes).use(attemptRoutes).use(progressRoutes).use(statisticsRoutes).use(monitoringRoutes).use(quizAttemptRoutes).use(quizStatisticsRoutes);
//#endregion
//#region src/index.ts
const app = new Elysia().use(cors({
	origin: (request) => {
		const origin = request.headers.get("origin");
		if (!origin) return false;
		if (origin.startsWith("http://localhost:") || origin === "https://budayana-app.vercel.app") return true;
		return allowedOrigins.includes(origin);
	},
	methods: [
		"GET",
		"POST",
		"PATCH",
		"DELETE",
		"OPTIONS",
		"PUT"
	],
	allowedHeaders: [
		"Content-Type",
		"Authorization",
		"Accept",
		"Origin",
		"x-better-auth-session"
	],
	credentials: true
})).onError(({ error, set }) => {
	console.error("Elysia caught error:", error);
	const statusNum = typeof set.status === "number" ? set.status : parseInt(String(set.status || ""), 10);
	if (isNaN(statusNum) || statusNum < 100 || statusNum > 599) set.status = 500;
	return {
		error: (error && typeof error === "object" && "message" in error ? String(error.message) : String(error)) || "Internal Server Error",
		code: "INTERNAL_SERVER_ERROR"
	};
}).mount("/auth", auth.handler).use(openapi({
	references: fromTypes(),
	documentation: {
		components: await OpenAPI.components,
		paths: await OpenAPI.getPaths()
	}
})).use(apiRoutes).get("/", () => "OK");
if (process.env.NODE_ENV === "development" && !process.env.VERCEL) {
	app.listen(3e3);
	console.log("🚀 Server running at http://localhost:3000");
}
//#endregion
export { app as default };
